// ── Garde ────────────────────────────────────────────────────────────
if (instance.__billetRetourBound) return;
instance.__billetRetourBound = true;
console.log('[BILLET-RETOUR] 🚀 CustomAction chargé');

var CUSTOM_SCHEMA = JSON.stringify({
  "pays_provenance": "Le nom du pays de destination du vol retour",
  "aeroport_iata":   "Le code IATA de l'aéroport de destination (3 lettres)",
  "aeroport_nom":    "Le nom de l'aéroport de destination",
  "compagnie":       "Le nom complet de la compagnie aérienne",
  "numero_vol":      "Le numéro de vol (ex: AF447, ET500, LH123)"
});

var TICKET_URL_RETOUR = 'https://64cb-102-211-168-154.ngrok-free.app/api/v1/ticket-extraction/scan';

// ── Loader ───────────────────────────────────────────────────────────
function showLoader() {
  if (document.getElementById('billet-retour-loader')) return;
  if (!document.getElementById('mrz-spin-css')) {
    var st = document.createElement('style');
    st.id = 'mrz-spin-css';
    st.textContent = '@keyframes mrz-spin{to{transform:rotate(360deg)}}';
    document.head.appendChild(st);
  }
  var el = instance.element;
  if (!el) return;
  el.style.position = 'relative';
  var div = document.createElement('div');
  div.id = 'billet-retour-loader';
  div.style.cssText =
    'position:absolute;inset:0;background:rgba(255,255,255,.88);' +
    'display:flex;align-items:center;justify-content:center;' +
    'z-index:200;border-radius:14px;';
  div.innerHTML =
    '<div style="text-align:center">' +
    '<div style="width:34px;height:34px;border:3px solid #e5e7eb;' +
    'border-top-color:#006A4F;border-radius:50%;' +
    'animation:mrz-spin .8s linear infinite;margin:0 auto 10px"></div>' +
    '<p style="font-size:13px;color:#374151;font-family:Poppins,sans-serif;margin:0">' +
    'Analyse du billet\u2026</p></div>';
  el.appendChild(div);
}
function hideLoader() {
  var l = document.getElementById('billet-retour-loader');
  if (l) l.remove();
}

// ── Normalisation ────────────────────────────────────────────────────
function normalize(str) {
  if (!str) return '';
  return str.toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]/g, '');
}

// ── Remplissage aéroport retour ───────────────────────────────────────
// Note : valueProperty="name" pour aeroportProvenanceRetour
function fillAeroport(countryCode, iataCode, airportNom) {
  function tryFill() {
    if (!window.__airports) return false;
    var normIata = normalize(iataCode);
    var normNom  = normalize(airportNom);

    // 1. IATA exact en priorité
    var match = null;
    if (normIata) {
      match = window.__airports.find(function(a) {
        return a.iata && normalize(a.iata) === normIata;
      });
    }
    // 2. Nom dans le pays
    if (!match && normNom) {
      match = window.__airports.find(function(a) {
        var ccMatch = (a.cc === countryCode) ||
                      (a.cc && countryCode && a.cc === countryCode.substring(0, 2));
        return ccMatch && normalize(a.name).indexOf(normNom) !== -1;
      });
    }
    // 3. Nom global
    if (!match && normNom) {
      match = window.__airports.find(function(a) {
        return normalize(a.name).indexOf(normNom) !== -1;
      });
    }

    if (match) {
      var aerComp = instance.root.getComponent('aeroportProvenanceRetour');
      if (aerComp) {
        // valueProperty="name" → on passe le nom directement
        aerComp.setValue(match.name || match);
        console.log('[BILLET-RETOUR] ✅ aeroportProvenanceRetour =', match.name, '(' + match.iata + ')');
        return true;
      }
    }
    return false;
  }

  if (!tryFill()) {
    var tries = 0;
    var t = setInterval(function() {
      tries++;
      if (tries > 12 || tryFill()) clearInterval(t);
    }, 500);
  }
}

// ── Préremplissage principal ─────────────────────────────────────────
function prefillFromBilletRetour(d) {
  if (!d) return;
  console.log('[BILLET-RETOUR] ✅ Préremplissage:', JSON.stringify(d));
  hideLoader();
  var root = instance.root;

  // Numéro de vol
  if (d.numero_vol) {
    var volComp = root.getComponent('numeroVolRetour');
    if (volComp) { volComp.setValue(d.numero_vol); console.log('[BILLET-RETOUR] ✅ numeroVolRetour =', d.numero_vol); }
    else console.warn('[BILLET-RETOUR] ❌ numeroVolRetour introuvable');
  }

  // Compagnie
  if (d.compagnie) {
    var normComp = normalize(d.compagnie);
    fetch('https://api-citizen-voyage.sandbox.gouv.tg/api/v1/constants/airlines', {
      headers: { 'ngrok-skip-browser-warning': 'true' }
    })
      .then(function(r) { return r.json(); })
      .then(function(json) {
        var list = json.data || json;
        var found = list.find(function(a) { return normalize(a.label || a.name || '') === normComp; });
        if (!found) found = list.find(function(a) {
          var l = normalize(a.label || a.name || '');
          return l.indexOf(normComp) !== -1 || normComp.indexOf(l) !== -1;
        });
        if (found) {
          var compComp = root.getComponent('compagnieRetour');
          if (compComp) { compComp.setValue(found.label || found.value || found); console.log('[BILLET-RETOUR] ✅ compagnieRetour =', found.label); }
          else console.warn('[BILLET-RETOUR] ❌ compagnieRetour introuvable');
        } else { console.warn('[BILLET-RETOUR] ❌ Compagnie non trouvée:', d.compagnie); }
      }).catch(function(e) { console.warn('[BILLET-RETOUR] ❌ Fetch compagnies:', e); });
  }

  // Pays → puis aéroport
  if (d.pays_provenance) {
    var normPays = normalize(d.pays_provenance);
    fetch('https://api-citizen-voyage.sandbox.gouv.tg/api/v1/constants/countries')
      .then(function(r) { return r.json(); })
      .then(function(json) {
        var list = json.data || json;
        var found = list.find(function(c) {
          return normalize(c.name) === normPays || normalize(c.name_fr || '') === normPays;
        });
        if (!found) found = list.find(function(c) {
          return normalize(c.name).indexOf(normPays) !== -1 || normPays.indexOf(normalize(c.name)) !== -1;
        });
        if (found) {
          var paysComp = root.getComponent('paysProvenanceRetour');
          if (paysComp) {
            paysComp.setValue(found);
            console.log('[BILLET-RETOUR] ✅ paysProvenanceRetour =', found.name);
            if (d.aeroport_iata || d.aeroport_nom) {
              setTimeout(function() {
                fillAeroport(found.code, d.aeroport_iata, d.aeroport_nom);
              }, 1200);
            }
          } else { console.warn('[BILLET-RETOUR] ❌ paysProvenanceRetour introuvable'); }
        } else { console.warn('[BILLET-RETOUR] ❌ Pays non trouvé:', d.pays_provenance); }
      }).catch(function(e) { console.warn('[BILLET-RETOUR] ❌ Fetch pays:', e); });
  }
}

// Exposer pour debug
window.__prefillFromBilletRetour = prefillFromBilletRetour;

// ── Patch XHR retour ─────────────────────────────────────────────────
// Flag séparé du billet entrée pour ne pas entrer en conflit
if (!window.__billetRetourXHRPatched) {
  window.__billetRetourXHRPatched = true;

  // Récupérer le XHR actuel (peut déjà être patché par le billet entrée)
  var _CurrentXHR = window.XMLHttpRequest;

  function BilletRetourXHR() {
    var xhr  = new _CurrentXHR();
    var _url = '';
    var _origOpen = xhr.open.bind(xhr);
    xhr.open = function(method, url) {
      _url = url || '';
      return _origOpen.apply(xhr, arguments);
    };
    var _origSend = xhr.send.bind(xhr);
    xhr.send = function(body) {
      if (_url.indexOf('/ticket-extraction/scan') !== -1 && body instanceof FormData) {
        if (!body.has('custom_schema')) {
          body.append('custom_schema', CUSTOM_SCHEMA);
          console.log('[BILLET-RETOUR] ✅ custom_schema injecté');
        }
      }
      return _origSend.call(xhr, body);
    };
    xhr.addEventListener('load', function() {
      // Intercepter uniquement les appels vers l'URL retour
      if (_url.indexOf('/ticket-extraction/scan') !== -1 &&
          _url.indexOf('64cb-') !== -1 &&
          xhr.status >= 200 && xhr.status < 300) {
        try {
          var resp = JSON.parse(xhr.responseText);
          console.log('[BILLET-RETOUR] 📡 Réponse:', JSON.stringify(resp).substring(0, 300));
          var extracted = (resp && resp.data) ? resp.data
                        : (resp && resp.extracted) ? resp.extracted
                        : (resp && resp.result) ? resp.result : null;
          if (extracted) {
            prefillFromBilletRetour(extracted);
          } else {
            console.warn('[BILLET-RETOUR] ❌ Pas de data dans la réponse');
          }
        } catch(e) { console.warn('[BILLET-RETOUR] Parse XHR échoué:', e); }
      }
    });
    return xhr;
  }

  BilletRetourXHR.prototype = _CurrentXHR.prototype;
  for (var k in _CurrentXHR) { try { BilletRetourXHR[k] = _CurrentXHR[k]; } catch(e){} }
  window.XMLHttpRequest = BilletRetourXHR;
  console.log('[BILLET-RETOUR] ✅ XHR patché');
}

// ── Loader sur input file ─────────────────────────────────────────────
function bindInput() {
  var el = instance.element;
  if (!el) return;
  var input = el.querySelector('input[type="file"]');
  if (!input || input.__billetRetourLoaderBound) return;
  input.__billetRetourLoaderBound = true;
  input.addEventListener('change', function(e) {
    if (e.target.files && e.target.files.length > 0) {
      console.log('[BILLET-RETOUR] 📎 Fichier:', e.target.files[0].name);
      showLoader();
    }
  });
}

bindInput();
setTimeout(bindInput, 300);
setTimeout(bindInput, 1000);

console.log('[BILLET-RETOUR] ✅ Prêt');

