// Attacher le click handler sur le div trigger
function bindBtn() {
  var trigger = document.querySelector('.btn-ajouter-trigger');
  if (!trigger || trigger.__bound) return;
  trigger.__bound = true;
  trigger.addEventListener('click', function() {
    // Chercher l'instance editgrid mesProfils
    var eg = null;
    var root = instance.root || instance;
    if (root && root.getComponent) {
      eg = root.getComponent('mesProfils');
    }
    if (!eg) {
      var p = instance.parent;
      while (p) {
        if (p.getComponent) { eg = p.getComponent('mesProfils'); if (eg) break; }
        p = p.parent;
      }
    }
    if (eg && eg.addRow) {
      eg.addRow();
    } else {
      // fallback: cliquer le vrai bouton addRow
      var btn = document.querySelector('[ref="addRow"]')
             || document.querySelector('.formio-component-mesProfils button');
      if (btn) btn.click();
    }
  });
}
setTimeout(bindBtn, 300);
setTimeout(bindBtn, 800);
setTimeout(bindBtn, 1500);

