actions.customAction:
function bindSave() {
  var saveBtn = document.getElementById('voy-btn-save');
  if (!saveBtn || saveBtn.__bound) return;
  saveBtn.__bound = true;
  saveBtn.addEventListener('click', function() {
    // Cliquer sur le bouton natif Enregistrer du dialog Formio
    var nativeBtn = document.querySelector('.formio-dialog-content > .btn.btn-primary');
    if (nativeBtn) {
      // Le rendre temporairement visible pour pouvoir cliquer
      nativeBtn.style.setProperty('display', 'block', 'important');
      nativeBtn.click();
      nativeBtn.style.removeProperty('display');
    }
  });
}
setTimeout(bindSave, 300);
setTimeout(bindSave, 800);
setTimeout(bindSave, 1500);

setTimeout(function() {
  function goToPageByKey(pageKey) {
    try {
      var forms = Object.values(Formio.forms || {});
      if (!forms || forms.length === 0) return;
      var form = forms[0];
      form.setPage(pageKey === 'information_du_voyage' ? 0 : 1);
      window.scrollTo(0,0);
    } catch(e) { console.error(e); }
  }
  var btnV = document.getElementById('modifier-info-voyage');
  if (btnV) btnV.onclick = function() { goToPageByKey('information_du_voyage'); };
  document.querySelectorAll('[id^="modifier-voyageur-"]').forEach(function(btn) {
    btn.onclick = function() { goToPageByKey('InformationVoyageurs'); };
  });
}, 800);

function rcGotoPage(idx) {
  // setTimeout pour s'exécuter APRÈS le handler natif du wizard
  setTimeout(function(){
    try {
      var w = Object.values(Formio.forms||{}).find(function(f){
        return f.pages && f.pages.length > 1;
      });
      if(!w) return;
      // Désactiver temporairement la validation
      var oldCheckPage = w.checkCurrentPageValidity;
      w.checkCurrentPageValidity = function(){ return true; };
      w.setPage(idx);
      w.checkCurrentPageValidity = oldCheckPage;
      window.scrollTo(0,0);
    } catch(e){ console.warn('[RC]',e); }
  }, 0);
}

var el1 = document.getElementById('modifier-info-voyage');
if(el1){
  el1.onclick = function(e){
    e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation();
    rcGotoPage(1);
    return false;
  };
}

document.querySelectorAll('[id^="modifier-voyageur-"]').forEach(function(el){
  el.onclick = function(e){
    e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation();
    rcGotoPage(3);
    return false;
  };
});

