var MOIS=['Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'];
if(!window._voyInit){
  window._voyInit=true;

  function mois(n){var i=parseInt(n,10);return(i>=1&&i<=12)?MOIS[i-1]:n;}
