    if(!iso)return'—';var p=iso.split('-');
    if(p.length!==3)return iso;
    return parseInt(p[2])+' '+mois(p[1])+' '+p[0];
  }
  function isoToDay(iso){
    if(!iso)return'';var p=iso.split('-');
    if(p.length!==3)return'';
    return pad2(p[2])+'/'+pad2(p[1])+'/'+p[0];
  }

  if(!document.getElementById('voy-ui-css')){
    var uiSt=document.createElement('style');
    uiSt.id='voy-ui-css';
    uiSt.textContent='@keyframes voySpin{to{transform:rotate(360deg)}}@keyframes voyFadeIn{from{opacity:0;transform:translateY(-8px)}to{opacity:1;transform:none}}#voy-fetch-loader{position:fixed;inset:0;background:rgba(255,255,255,.88);z-index:999998;display:flex;align-items:center;justify-content:center}#voy-fetch-loader .spin{width:44px;height:44px;border:4px solid #e5e7eb;border-top-color:#006A4F;border-radius:50%;animation:voySpin .8s linear infinite}#voy-fetch-loader p{font-family:Poppins,sans-serif;color:#374151;font-size:14px;margin:12px 0 0;text-align:center}#voy-toast{position:fixed;top:24px;left:50%;transform:translateX(-50%);z-index:999999;background:#1E2939;color:#fff;padding:12px 24px;border-radius:10px;font-family:Poppins,sans-serif;font-size:14px;font-weight:500;box-shadow:0 4px 24px rgba(0,0,0,.18);display:none;animation:voyFadeIn .25s ease}#voy-toast.err{background:#dc2626}#voy-toast.warn{background:#d97706}';
    document.head.appendChild(uiSt);
  }

  function showFetchLoader(){
    if(document.getElementById('voy-fetch-loader'))return;
    var el=document.createElement('div');el.id='voy-fetch-loader';
    el.innerHTML='<div style="text-align:center"><div class="spin"></div><p>Recherche des informations en cours…</p></div>';
    document.body.appendChild(el);
  }
  function hideFetchLoader(){var el=document.getElementById('voy-fetch-loader');if(el)el.remove();}

  var _toastTimer=null;
  function showToast(msg,type,dur){
    var el=document.getElementById('voy-toast');
    if(!el){el=document.createElement('div');el.id='voy-toast';document.body.appendChild(el);}
    el.textContent=msg;el.className=type||'';el.style.display='block';
    if(_toastTimer)clearTimeout(_toastTimer);
    _toastTimer=setTimeout(function(){el.style.display='none';},dur||4000);
  }

  function hideSaveBtn(){
    var btn=document.querySelector('.formio-dialog-content > .btn.btn-primary');
    if(btn)btn.style.setProperty('display','none','important');
  }
  function showSaveBtn(){
    var btn=document.querySelector('.formio-dialog-content > .btn.btn-primary');
    if(btn)btn.style.removeProperty('display');
  }
  function showAndClickSave(){
    var btn=document.querySelector('.formio-dialog-content [ref="saveRow"]')
      ||document.querySelector('.formio-dialog-content .editgrid-row-modal-save')
      ||document.querySelector('.formio-dialog-content .btn-primary');
    if(btn){btn.style.removeProperty('display');btn.removeAttribute('disabled');btn.click();}
  }
  window._voyNativeSave=showAndClickSave;

  function goTab(idx){
    var tabs=document.querySelector('.formio-component-tabs');
    if(!tabs)return;
    var l=tabs.querySelectorAll('.nav-tabs .nav-link');
    if(l.length>idx)l[idx].click();
  }

  function getCurrentEditRow(){
    var f=(Object.values(Formio.forms||{})||[])[0];if(!f)return null;
    var eg=f.getComponent('voyageurs');if(!eg)return null;
    var idx=(eg.editRows||[]).findIndex(function(r){return r.state==='editing'||r.state==='new';});
    return idx>=0?eg.editRows[idx]:null;
  }

  function findAndSet(comps,key,val){
    if(!comps)return;
    comps.forEach(function(c){
      if(!c)return;
      if(c.component&&c.component.key===key){
        try{c.setValue(val,{noUpdateEvent:true,noValidate:true});}catch(e){}
      }
      if(c.components)findAndSet(c.components,key,val);
      if(c.rows)c.rows.forEach(function(r){findAndSet(r,key,val);});
      if(c.columns)c.columns.forEach(function(col){if(col.components)findAndSet(col.components,key,val);});
    });
  }

  window.mrzHide=function(){var o=document.getElementById('mrz-overlay');if(o)o.style.display='none';};
  window._mrzFoundData=null;

  window.mrzFillFromApi=function(fd){
    var n=document.getElementById('mrz-nom');if(!n)return;
    n.textContent=((fd.nom||'')+' '+(fd.prenoms||'')).trim()||'—';
    var dob=document.getElementById('mrz-dob');if(dob)dob.textContent=isoToLabel(fd.dateNaissance);
    var t=document.getElementById('mrz-type');if(t)t.textContent=fd.typeDocument||'—';
    var nu=document.getElementById('mrz-num');if(nu)nu.textContent=fd.numeroDocument||'—';
    var ex=document.getElementById('mrz-exp');if(ex)ex.textContent=isoToLabel(fd.dateExpirationDocument);
  };

  window.mrzUse=function(){
    window.mrzHide();
    var vData=window._mrzFoundData;
    if(!vData)return goTab(1);
    var er=getCurrentEditRow();
    if(er&&er.data){
      var d=er.data;
      var tel=vData.telephone||'';
      var indicatif='+228',numero=tel;
      var indics=['+228','+229','+233','+221','+225','+237','+226','+227','+224','+223',
        '+234','+243','+242','+241','+235','+236','+213','+212','+216','+20','+27',
        '+254','+255','+256','+251','+250','+257','+253','+252','+261','+258','+260',
        '+263','+264','+267','+268','+266','+244','+239','+238','+240','+269','+248',
        '+230','+265','+220','+245','+232','+231','+33','+44','+49','+34','+39','+32',
        '+31','+351','+41','+43','+48','+46','+47','+45','+358','+40','+7','+966',
        '+971','+972','+962','+961','+964','+98','+92','+880','+94','+66','+84','+62',
        '+60','+65','+63','+82','+81','+86','+91','+61','+64','+55','+52','+54','+57',
        '+51','+58','+56','+593','+591','+595','+598'];
      for(var ii=0;ii<indics.length;ii++){
        if(tel.startsWith(indics[ii])){indicatif=indics[ii];numero=tel.slice(indics[ii].length);break;}
      }
      d.nom=vData.nom||'';d.prenoms=vData.prenoms||'';d.sexe=vData.sexe||'';
      d.lieuNaissance=vData.lieuNaissance||'';d.profession=vData.profession||'';
      d.email=vData.email||'';
      d.telephoneWrapper={indicatif:indicatif,numero:numero};
      d.adresseEtranger=vData.adresseEtranger||'';d.adresseTogo=vData.adresseTogo||'';
      d.nomPere=vData.nomPere||'';d.nomMere=vData.nomMere||'';
      d.nomUrgence=(vData.contactUrgence&&vData.contactUrgence.nom)||'';
      d.telephoneUrgence=(vData.contactUrgence&&vData.contactUrgence.telephone)||'';
      d.dateNaissance=isoToDay(vData.dateNaissance);
      if(er.components){
        findAndSet(er.components,'nom',d.nom);
        findAndSet(er.components,'prenoms',d.prenoms);
        findAndSet(er.components,'sexe',d.sexe);
        findAndSet(er.components,'dateNaissance',d.dateNaissance);
        findAndSet(er.components,'lieuNaissance',d.lieuNaissance);
        findAndSet(er.components,'profession',d.profession);
        findAndSet(er.components,'email',d.email);
        findAndSet(er.components,'telephoneWrapper',d.telephoneWrapper);
        findAndSet(er.components,'adresseEtranger',d.adresseEtranger);
        findAndSet(er.components,'adresseTogo',d.adresseTogo);
        findAndSet(er.components,'nomPere',d.nomPere);
        findAndSet(er.components,'nomMere',d.nomMere);
        findAndSet(er.components,'nomUrgence',d.nomUrgence);
        findAndSet(er.components,'telephoneUrgence',d.telephoneUrgence);
      }
    }
    goTab(1);
  };

  window.mrzShow=function(){
    var er=getCurrentEditRow();
    var d=(er&&er.data)||{};
    var errors=[];
    var pe=d.paysEmetteur||{};
    var country=pe.code||pe.cca2||pe.cca3||(typeof pe==='string'?pe:'');
    if(!country)errors.push('le pays émetteur');
    if(!d.typeDocument)errors.push('le type de document');
    if(!d.numeroDocument||!d.numeroDocument.trim())errors.push('le numéro de document');
    var expRaw=d.dateExpirationDocument||'';
    var expISO='';
    if(expRaw&&expRaw!=='00/00/0000'){
      var p=expRaw.split('/');
      if(p.length===3&&parseInt(p[2])>0)expISO=p[2]+'-'+pad2(p[1])+'-'+pad2(p[0]);
    }
    if(!expISO)errors.push("la date d'expiration du document");
    if(errors.length>0){
      showToast('⚠️ Veuillez renseigner '+errors.join(', ')+' avant de continuer.','warn',5000);
      return;
    }
    window._mrzFoundData=null;
    showFetchLoader();
    fetch('https://pgx851gn-4001.uks1.devtunnels.ms/api/v1/records/public/voyage/form-data',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({
        documentNumber:d.numeroDocument||'',
        issuingCountry:country,
        expirationDate:expISO,
        documentType:d.typeDocument||''
      })
    })
    .then(function(r){return r.ok?r.json():Promise.reject('HTTP '+r.status);})
    .then(function(json){
      hideFetchLoader();
      var vList=json&&json.data&&json.data.formData&&json.data.formData.voyageurs;
      window._mrzFoundData=(vList&&vList.length>0)?vList[0]:null;
      if(!window._mrzFoundData){
        showToast('ℹ️ Aucun dossier trouvé pour ce document. Remplissez les informations manuellement.','',5000);
        goTab(1);return;
      }
      window.mrzFillFromApi(window._mrzFoundData);
      var overlay=document.getElementById('mrz-overlay');
      if(overlay)overlay.style.display='flex';
    })
    .catch(function(e){
      hideFetchLoader();
      console.warn('[MRZ]',e);
      showToast("⚠️ Impossible de vérifier le document. Passez à l'étape suivante.",'warn',5000);
      goTab(1);
    });
  };

  function onTabChange(){
    var tabs=document.querySelector('.formio-component-tabs');
    if(!tabs)return;
    var links=tabs.querySelectorAll('.nav-tabs .nav-link');
    links.forEach(function(link){
      if(!link._tabBound){link._tabBound=true;link.addEventListener('click',function(){setTimeout(hideSaveBtn,100);});}
    });
  }

  function bindAll(){
    var prev  =document.getElementById('voy-btn-prev');
    var next  =document.getElementById('voy-btn-next');
    var close =document.getElementById('mrz-close');
    var refuse=document.getElementById('mrz-btn-refuse');
    var use   =document.getElementById('mrz-btn-use');
    var prev2 =document.getElementById('voy-btn-prev2');
    var save  =document.getElementById('voy-btn-save');

    if(prev&&!prev._b){prev._b=true;prev.addEventListener('click',function(){
      var p=document.querySelector('[ref="previous"]')||document.querySelector('.btn-wizard-nav-previous');
      if(p)p.click();
    });}
    if(next&&!next._b){next._b=true;next.addEventListener('click',window.mrzShow);}
    if(close&&!close._b){close._b=true;close.addEventListener('click',window.mrzHide);}
    if(refuse&&!refuse._b){refuse._b=true;refuse.addEventListener('click',function(){window.mrzHide();goTab(1);});}
    if(use&&!use._b){use._b=true;use.addEventListener('click',window.mrzUse);}
    if(prev2&&!prev2._b){prev2._b=true;prev2.addEventListener('click',function(){goTab(0);});}
    if(save&&!save._b){save._b=true;save.addEventListener('click',function(){
      showSaveBtn();
      var realSave=document.querySelector('.formio-dialog-content > .btn.btn-primary');
      if(realSave){realSave.style.removeProperty('display');realSave.click();}
    });}
    hideSaveBtn();onTabChange();
  }

  setTimeout(bindAll,300);setTimeout(bindAll,800);setTimeout(bindAll,1500);
  new MutationObserver(function(){bindAll();}).observe(document.body,{childList:true,subtree:true});
}

