validate.custom:
if (!input || input === '00/00/0000') { valid = ''; }
else {
  var parts = input.split('/');
  var jour = parseInt(parts[0], 10);
  var mois = parseInt(parts[1], 10);
  var annee = parseInt(parts[2], 10);
  if (!jour || !mois || !annee || jour < 1 || jour > 31 || mois < 1 || mois > 12) {
    valid = 'La date de naissance est invalide';
  } else {
    var dateNaissance = new Date(annee, mois - 1, jour);
    var today = new Date();
    today.setHours(0, 0, 0, 0);
    if (dateNaissance >= today) {
      valid = 'La date de naissance ne peut pas être supérieur à la date du jour';
    } else {
      var age = today.getFullYear() - dateNaissance.getFullYear();
      var moisDiff = today.getMonth() - dateNaissance.getMonth();
      var jourDiff = today.getDate() - dateNaissance.getDate();
      if (moisDiff < 0 || (moisDiff === 0 && jourDiff < 0)) { age--; }
      if (age > 120) {
        valid = 'La date de naissance semble incorrecte (âge supérieur à 120 ans)';
      } else {
        valid = true;
      }
    }
  }
}
